const attachments = $input.item.json.attachments || [];

const notesDoc = attachments.find(a => a.title === "Notes by Gemini");

return [{
  json: {
    notesFileId: notesDoc?.fileId || null,
    notesFound: !!notesDoc,
  }
}];

const output = $('AI Agent').item.json.output;
const url = typeof output === 'string' ? output : output['editor URL'];
const shadowFormId = url.split('/').pop();

// Step 1: Fetch shadow form spec
const spec = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.weavely.ai/forms/${shadowFormId}/client`,
  headers: {
    'Accept': 'application/json'
  }
});

// Step 2: Create anonymous copy owned by the user
const newForm = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.weavely.ai/v1/forms',
  headers: {
    'Content-Type': 'application/json',
    'Origin': 'https://forms.weavely.ai',
    'Referer': 'https://forms.weavely.ai/'
  },
  body: JSON.stringify({
    name: spec.name || 'Post-Meeting Survey',
    publish: false,
    formJSON: spec.formJSON,
    themeJSON: spec.themeJSON,
    settings: spec.settings,
    logicRules: spec.logicRules || [],
    eventTriggers: spec.eventTriggers || []
  })
});

return [{
  json: {
    shareUrl: 'https://forms.weavely.ai/' + newForm.id,
    claimUrl: newForm.editor + '?publish=true',
    formId: newForm.id
  }
}];

